/// <summary>
/// Extension class of form <c>PurchAgreement</c> datasource <c>AgreementHeaderDefault</c>
/// </summary>
[ExtensionOf(formDataSourceStr(PurchAgreement, AgreementHeaderDefault))]
internal final class ETGPurchAgreemenAgreementHeaderDefaultFormDS_Extension
{
}

Method.Source:
public int active()
{
    int ret = next active();

    if(ETGACFParameters::find().EnableMandatoryFields == NoYes::Yes)
    {
       FormDataSource      purchAgreement_ds                    = any2Object(this) as FormDataSource;
       AgreementHeaderDefault agreementHeaderDefault = purchAgreement_ds.cursor();

        purchAgreement_ds.object(fieldNum(AgreementHeaderDefault, PaymentTerms)).mandatory(true);
        purchAgreement_ds.object(fieldNum(AgreementHeaderDefault, DeliveryMode)).mandatory(true);
        purchAgreement_ds.object(fieldNum(AgreementHeaderDefault, DeliveryTerm)).mandatory(true);
    }
    return ret;
}

public boolean validateWrite()
{
    boolean ret = next validateWrite();

    if (ret)
    {
        if (ETGACFParameters::find().EnableMandatoryFields == NoYes::Yes)
        {
            FormDataSource      agrLines         = any2Object(this) as FormDataSource;
            formRun             formRun                         = agrLines.formRun();
            ret= ETGPurchAgreementMandatoryValidation::validateFormHeaders(formRun);
        }
    }

    return true;
}
